import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { userService, patientService, doctorService, appointmentService, billingService } from '../services/api';
import '../styles/auth.css';

const AdminDashboard = () => {
    const navigate = useNavigate();
    const [activeMenu, setActiveMenu] = useState('overview');
    const [patients, setPatients] = useState([]);
    const [doctors, setDoctors] = useState([]);
    const [appointments, setAppointments] = useState([]);
    const [billings, setBillings] = useState([]);
    const [loading, setLoading] = useState(false);
    const [showForm, setShowForm] = useState(false);
    const [formData, setFormData] = useState({});
    const [editingId, setEditingId] = useState(null);

    useEffect(() => {
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            const [pRes, dRes, aRes, bRes] = await Promise.all([
                patientService.getPatients().catch(() => ({ data: { results: [] } })),
                doctorService.getDoctors().catch(() => ({ data: { results: [] } })),
                appointmentService.getAppointments().catch(() => ({ data: { results: [] } })),
                billingService.getBillings().catch(() => ({ data: { results: [] } }))
            ]);
            setPatients(pRes?.data?.results || pRes?.data || []);
            setDoctors(dRes?.data?.results || dRes?.data || []);
            setAppointments(aRes?.data?.results || aRes?.data || []);
            setBillings(bRes?.data?.results || bRes?.data || []);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = () => {
        if (window.confirm('Are you sure you want to logout?')) {
            localStorage.removeItem('access_token');
            localStorage.removeItem('refresh_token');
            localStorage.removeItem('user');
            navigate('/login');
        }
    };

    const handleDelete = async (id, type) => {
        if (!window.confirm(`Delete this ${type}?`)) return;
        try {
            if (type === 'patient') {
                await patientService.updatePatient(id, { is_active: false });
            } else if (type === 'doctor') {
                await doctorService.updateDoctor(id, { is_available: false });
            }
            loadDashboardData();
            alert(`${type} deleted successfully`);
        } catch (error) {
            alert(`Failed to delete ${type}`);
        }
    };

    const stats = [
        { label: 'Total Patients', value: patients.length, icon: '👥', color: '#3498db' },
        { label: 'Total Doctors', value: doctors.length, icon: '👨‍⚕️', color: '#2ecc71' },
        { label: 'Appointments', value: appointments.length, icon: '📅', color: '#f39c12' },
        { label: 'Billings', value: billings.length, icon: '💰', color: '#e74c3c' }
    ];

    return React.createElement(
        'div',
        { style: { display: 'flex', minHeight: '100vh', backgroundColor: '#ecf0f1' } },
        // Sidebar
        React.createElement(
            'div',
            { style: { width: '250px', backgroundColor: '#2c3e50', color: 'white', padding: '20px', overflowY: 'auto' } },
            React.createElement('div', { style: { fontSize: '24px', fontWeight: 'bold', marginBottom: '30px', paddingBottom: '20px', borderBottom: '1px solid #34495e' } }, '🏥 Admin Panel'),
            React.createElement(
                'nav',
                { style: { display: 'flex', flexDirection: 'column', gap: '10px' } },
                ['overview', 'patients', 'doctors', 'appointments', 'billings'].map(menu =>
                    React.createElement('button', {
                        key: menu,
                        onClick: () => setActiveMenu(menu),
                        style: {
                            padding: '12px',
                            border: 'none',
                            backgroundColor: activeMenu === menu ? '#3498db' : 'transparent',
                            color: 'white',
                            cursor: 'pointer',
                            borderRadius: '5px',
                            textAlign: 'left',
                            fontSize: '14px',
                            transition: 'all 0.3s'
                        },
                        onMouseOver: (e) => e.target.style.backgroundColor = e.target.style.backgroundColor || '#34495e',
                        onMouseOut: (e) => e.target.style.backgroundColor = activeMenu === menu ? '#3498db' : 'transparent'
